var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SIGMA_RAS_OPR_NULL","text":{"KOREA":"여기는 이번 항해의 종착지! 그라운드 원 선착장입니다!","JPN":"ここは今回の航海の終着地！　グラウンド・ワンの船着場です！","ENG":"Ladies and gentlemen, we've reached the final destination of this trip! Ground One!","TWN":"這裡就是這次航程的終點站！G1碼頭！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L3_1","type":"dialog","speaker":"SIGMA_RAS_OPR_NULL","text":{"KOREA":"다들 잊어 버린 물건 없이 조심해서 내려야 돼?","JPN":"みんな忘れ物はない？　気をつけて降りてね！","ENG":"Please make sure you take all your belongings with you.","TWN":"離開時請記得帶走隨身物品喔～"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"하하, 오랜만의 격렬한 전투였어! 그런데 베어링과 오일이 좀 새는 것 같구만!","JPN":"ガハハ、久々の激しい戦闘だったな！　ところで、どうやらオイルが少しずつ漏れているようだぞ！","ENG":"Haha! I haven't had a battle that fierce for the longest time! I think I'm missing a few bearings though… and I've got an oil leak!","TWN":"呵呵！好久沒遇到這麼激烈的戰鬥！不過軸承好像有點漏油!"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_TOUCH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"부품 교환 좀 도와주겠나? 정비사 친구!","JPN":"少し部品交換を手伝ってくれないか？　整備士の友よ！","ENG":"Could you give me a hand with the repairs? My dear grease monkey friend!","TWN":"可以幫我換一下零件嗎？維修師朋友！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"와와와와! 체르노바 소장님한테 연락드릴 테니까 가만히 계세요!","JPN":"うわわわわっ！　チェルノワ所長に連絡を入れるのでそのままにしてください！","ENG":"Woah, woah, woah! Please stay still while I reach out to Director Chernova!","TWN":"哎呀呀！我會再跟切爾諾娃所長聯絡，你先不要亂動。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"움직이면 안 된다니까요! 갑판이 찌그러져요!","JPN":"動いちゃダメなのです！　デッキが凹みますよ！","ENG":"Please keep still! You'll dent the deck!","TWN":"你不要亂動啦！甲板會壞掉！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"……다들 귀환을 환영합니다.","JPN":"……皆さんの帰還を歓迎します。","ENG":"…Welcome back, everyone.","TWN":"……歡迎大家回來。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"주시윤 군도 무사한 걸 보니 작전은 성공적이었던 것 같네요.","JPN":"アキヤマ君も無事ということは、作戦は成功だったようですね。","ENG":"Seeing as Shiyoon came back in one piece, I take it that the mission was a success.","TWN":"周時雲也一起平安回來，看來是作戰成功囉？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"서윤 양의 무단 이탈에 대해서는 따로 사장님께 전달 받았습니다.","JPN":"アオイ・シズカさんの無断離脱については別途社長から連絡がありました。","ENG":"As for you, Seo Yoon, the President has informed me about you going AWOL.","TWN":"至於徐芸擅離職守一事，我有另外收到老闆的通知。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그렇다고 그냥 넘어갈 수는 없고, 시말서 정도로 타협하기로 하지요.","JPN":"だからといって見過ごすわけにはいかないので、始末書程度で妥協することにしましょう。","ENG":"But that doesn't mean I'll let this slide completely. A written statement will do for now.","TWN":"但也不能就這樣放過你，起碼要寫個悔過書才行。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아카데미 학생 분들도 본의 아니게 휘말리셔서 수고가 많았습니다.","JPN":"不本意に巻き込まれたアカデミー生徒の皆さんも、本当にお疲れ様でした。","ENG":"And as for the Academy students, thank you for your support, despite becoming unwittingly embroiled in this incident.","TWN":"這次的事學院的學生也不慎涉入其中，辛苦你們了。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"차편을 준비해 뒀으니 편하실 때 돌아가시면 됩니다.","JPN":"車を用意しているので、お帰りになる時お使いください。","ENG":"I've prepared a ride back for you, so please leave at your leisure.","TWN":"車子已經準備好了，你們隨時可以離開。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아, 며칠 후에 관리국에서 이번 건으로 사정청취를 진행할 예정이라는군요.","JPN":"それと、数日後に管理局から今回の件で事情聴取を行う予定だそうですね。","ENG":"By the way, the Administration will conduct a hearing about this incident in a few days.","TWN":"對了，過幾天管理局應該會針對此次事件，請你們進行說明。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"요식적인 절차이니 크게 부담 가질 필요는 없습니다.","JPN":"形式上のものなので、あまり負担を感じる必要はありません。","ENG":"It's nothing more than a perfunctory process, so no pressure.","TWN":"只是例行公事而已，大家不用太有壓力。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"아니, 잠깐! 설명은 그게 다야? 이건……","JPN":"いや待って！　説明はそれだけ？　これは……","ENG":"Wait! Is that all? I mean…","TWN":"等等！你要說的就這些而已嗎？……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아. 주시윤 군의 구출 작전에 협력한 대가는 회사에서 별도로 지급할 겁니다.","JPN":"ああ、アキヤマ君の救出作戦に協力いただいた報酬は、後日弊社から別途支給します。","ENG":"Oh. The company will make sure you are duly recompensed for your support in rescuing Shiyoon.","TWN":"哦～你們協助救出周時雲的代價，公司會另行支付。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그, 그게 아니라……!","JPN":"そ、そうじゃなくて……！","ENG":"Th-that's not what I'm talking about…","TWN":"我不是指這個啦……！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"미카, 나이엘 학생을 말려 주시겠어요?","JPN":"ミカさん、ナイエルさんを止めてもらえますか？","ENG":"Mika, would you please help contain Naielle?","TWN":"米卡，你可以讓奈爾同學安靜一下嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"앗, 네!","JPN":"あっ、はい！","ENG":"Oh, right!","TWN":"喔，是！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"나이엘 너도 회장님 말 들었지? 조용히 좀 있어 봐!","JPN":"ナイエル、会長の話を聞いたでしょ？　ちょっと静かにしてよ！","ENG":"You heard the President, Naielle! Keep quiet!","TWN":"奈爾你也有聽到會長的話吧？嘴巴閉起來！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L43_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"읍, 읍……!","JPN":"んぐっ、ぐっ……！","ENG":"Mmm! Mmph…!","TWN":"唔……！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"자, 그럼 다들 해산하죠.","JPN":"さあ、では全員解散でお願いします。","ENG":"All right then. That's all I've got.","TWN":"那大家就原地解散囉！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"다른 분들도 수고하셨습니다. 오늘은 쉬고, 다음주부터 출근하시면 됩니다.","JPN":"他の皆さんもお疲れ様でした。今日はゆっくり休んで、来週から出勤してください。","ENG":"Good job everyone. Take the rest of the day off. You can come back to work next week.","TWN":"其他人也辛苦了，今天大家就好好休息，下個禮拜再來上班吧！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"기다려.","JPN":"待って。","ENG":"Wait.","TWN":"等等！"},"stage":{"bg":"MAINSTREAM_7130012","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"MAINSTREAM_7130012","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"이대로 끝이라니, 그럴 리가 없잖아.","JPN":"このまま終わりだんて、そんなはずない。","ENG":"You can't expect us to just walk away without an explanation.","TWN":"就這樣嗎？哪有這樣的！"},"stage":{"bg":"MAINSTREAM_7130012","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"이 납치사건은 대체 뭐였던 거야?","JPN":"この誘拐事件はいったい何だったの？","ENG":"What was this abduction really about?","TWN":"這次的綁架事件到底是怎麼回事？！"},"stage":{"bg":"MAINSTREAM_7130012","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"왜 레이 선배가 날 죽인다는 거야? 세계를 부순다는 건 또 뭐고?","JPN":"なんでレイ先輩が私を殺そうとするの？　世界を滅ぼすってどういうこと？","ENG":"Why's Ray trying to kill me? And what did he mean about destroying the world?","TWN":"雷伊前輩為什麼說要殺我？還說要毀滅世界？"},"stage":{"bg":"MAINSTREAM_7130012","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그래서 알렌 선생님은, 레이 선배는 정체가 뭐야?","JPN":"あと、アレン先生、レイ先輩の正体はなに？","ENG":"Ray and Mr. Birmingham… Who are they, really?","TWN":"艾倫老師和雷伊前輩到底是誰？"},"stage":{"bg":"MAINSTREAM_7130012","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"왜 휘말린 사람들한테 설명 한마디 못 해 주는 거냐고!","JPN":"なんで巻き込まれた人たちに説明の一言もないのよ！！","ENG":"The least you could do is explain what we just went through!","TWN":"你難道不應該跟大家好好解釋一下嗎！"},"stage":{"bg":"MAINSTREAM_7130012","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"미나 양, 그건…….","JPN":"ミナさん、それは……","ENG":"About that, Mina…","TWN":"米娜，那是因為……"},"stage":{"bg":"MAINSTREAM_7130012","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이수연!","JPN":"カナミ・キズナ！","ENG":"Lee Sooyeon!","TWN":"李秀妍！"},"stage":{"bg":"MAINSTREAM_7130012","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"MAINSTREAM_7130012","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"스승님. 이번만큼은 스승님께서 직접 답해 주셔야 할 것 같군요.","JPN":"師匠。今回だけは師匠の口から直接答えてください。","ENG":"Master. I'm afraid it's about time you explained things yourself.","TWN":"師父，這次可能需要你親自解釋。"},"stage":{"bg":"MAINSTREAM_7130012","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"미나 양을 보호하고 싶은 마음은 알겠지만, 무작정 숨기기만 할 시기는 지났어요.","JPN":"ミナさんを守りたい気持ちはわかりますが、ひた隠しにする時期はもう過ぎました。","ENG":"I understand you wish to protect Mina, but we can't afford to hide this any longer.","TWN":"我明白師父想保護米娜的心，但現在已經無法再蒙混過去了。"},"stage":{"bg":"MAINSTREAM_7130012","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"이번엔 저들이 먼저 다가올 테니까요.","JPN":"今後は彼らのほうから近づいてきますから。","ENG":"Because next time… they'll come for us first.","TWN":"因為這次是他們主動找上門的。"},"stage":{"bg":"MAINSTREAM_7130012","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"MAINSTREAM_7130012","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"MAINSTREAM_7130012","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"레이라는 건, 그 소년이 아직 인간이었을 때의 이름이다.","JPN":"レイというのは、その少年がまだ人間だった時の名前だ。","ENG":"Ray was that boy's name… when he was still human.","TWN":"雷伊，是他還是人類的時候的名字。"},"stage":{"bg":"MAINSTREAM_7130013","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"인간이었을 때라니? 그럼 지금은 인간이 아니라는 거야?","JPN":"人間だった時？　それじゃあ今は人間じゃないっていうの？","ENG":"When he WAS human? You mean he's not human anymore?","TWN":"還是人類的時候？所以他現在不是人嗎？"},"stage":{"bg":"MAINSTREAM_7130013","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그래. 지금 그의 이름은 속삭이는 자, <color=#ffd34c>네헤모트</color>.","JPN":"そう。今の彼の名前は囁く者、<color=#ffd34c>ネヘモト</color>。","ENG":"Correct. His new name is <color=#ffd34c>Nehemoth</color> the Whisperer.","TWN":"沒錯，他現在的名字是私語者 <color=#ffd34c>貝赫莫特</color>。"},"stage":{"bg":"MAINSTREAM_7130013","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"가짜 구세주, 실패한 구원자라고도 불리는……","JPN":"偽の救世主、失敗した救世主とも呼ばれる……","ENG":"Also known as the False Savior, the Fallen Shepherd…","TWN":"也有人稱他是假救世主，失敗的救贖者……"},"stage":{"bg":"MAINSTREAM_7130013","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"클리포트의 마왕들 중 하나다.","JPN":"クリフォトの魔王の一人だ。","ENG":"He's one of the Demon Lords of Qliphoth.","TWN":"是逆卡巴拉的魔王之一。"},"stage":{"bg":"MAINSTREAM_7130013","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};